Actionscript.script:
子弹属性 = new Object();

子弹属性.声音 = "";
子弹属性.霰弹值 = 1;
子弹属性.子弹散射度 = 0;
子弹属性.发射效果 = "";
子弹属性.子弹种类 = "墨绿集束爆炸";
子弹属性.子弹威力 = this.子弹威力;
子弹属性.子弹速度 = 0;
子弹属性.击中地图效果 = "";
子弹属性.Z轴攻击范围 = 60;
子弹属性.击倒率 = 10;
子弹属性.击中后子弹的效果 = "";
子弹属性.子弹敌我属性 = this.子弹敌我属性值;
子弹属性.shootX = this._x;
子弹属性.shootY = this._y;
子弹属性.shootZ = this.Z轴坐标;
子弹属性.伤害类型 = "魔法";
子弹属性.魔法伤害属性 = "毒";
if(this.发射者名) 子弹属性.发射者 = this.发射者名;

_root.子弹区域shoot传递(子弹属性);

stop();
this.removeMovieClip();
